var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하아…… 하……","JPN":"はあ……は……","ENG":"*Huff...* *Huff...*","TWN":"呼呼……呼……"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"팔 하나로 검을 휘두르는 것은 한계가 명확하다.","JPN":"腕一本で刀を振るうのは限界がある。","ENG":"There is only so much one can do whilst wielding a sword with one hand.","TWN":"光靠一隻手臂要揮劍還是很有限的。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"고작 이런 힘으로는 당주님을 지키지 못해.","JPN":"こんな力では、当主を守れない。","ENG":"I will not be able to protect Lady Nanahara like this.","TWN":"我這樣是無法保護堂主的。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만 이걸 사용한다면…….","JPN":"だが、これを使えば……","ENG":"But if I use this...","TWN":"但是用這個的話……"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"비록 영혼을 해치는 힘이라고는 하나……","JPN":"たとえ魂を損ねる力であっても……","ENG":"Even if its power destroys my soul...","TWN":"雖然這股力量對靈魂有害……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"한계에 부딪혀 그 힘이 반드시 필요한 때가 오겠지.","JPN":"限界に達して、その力が必要になるときが来るだろう。","ENG":"There will be a time when I reach my limit and require its assistance.","TWN":"但當我面對到極限時就會需要它吧？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"그 앰플은 어디에서 난 거지?","JPN":"そのアンプルはどこから持ってきたのじゃ？","ENG":"Where did you get that ampule?","TWN":"你是從哪拿到那個東西的？"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……누구냐?!","JPN":"……何者だ！？","ENG":"...Who goes there?!","TWN":"……是誰？！"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"무슨 생각을 하는지 표정에서 다 드러나는구나, 하야미의 제자야.","JPN":"何を考えているのか全部顔に書いてあるのう、速水の弟子。","ENG":"Your expression says everything about what you're thinking, apprentice of Hayami.","TWN":"速水的徒弟，你想什麼都寫在你的臉上呢。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나오님……?","JPN":"ナオ様……？","ENG":"Miss Nao...?","TWN":"奈緒大人……？"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그건 힘의 원천 같은 게 아니다. 너를 영혼 없는 괴물로 만들 뿐이지.","JPN":"それは力の源なんかではない。お主を魂なき化け物にするだけじゃ。","ENG":"That is not a solution to getting stronger. It will only erode your soul and turn you into a monster.","TWN":"它不是力量的來源，它只會把你變成沒有靈魂的怪物。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만…… 그런 힘이 없으면 명부검을 휘두를 수조차 없습니다.","JPN":"しかし……そういう力がなければ、冥府剣を振るうことすらできません。","ENG":"But without... I cannot even unsheathe this sword.","TWN":"可是……沒有它，我連拿起冥府劍的力量都沒有。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"휘두르지 못하는 검으로는 아무것도 베지 못합니다.","JPN":"振るえない刀では何も斬ることができません。","ENG":"Being unable to wield it, I cannot strike anything.","TWN":"我拿不起劍就無法砍殺任何人。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"네가 원하는 힘이란 것은, 고작 적을 베기 위해서 필요한 것이냐?","JPN":"お主の望む力とは、たかが敵を斬るためだけに必要なものなのか？","ENG":"This power you seek, do you want it for the sole purpose of cutting down enemies?","TWN":"你之所以需要那股力量，只是因為要砍殺敵人嗎？"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……예?","JPN":"……はい？","ENG":"...Come again?","TWN":"……什麼？"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"검은 다만 벨 뿐이지만, 검술은 자고로 사람이 자신의 소중한 것을 지키기 위해 배우는 것.","JPN":"刀はただ斬るだけじゃが、剣術とは大切なものを守るために教わるものじゃ。","ENG":"A sword is meant to slice, but we hone the swordsmanship in order to protect the ones around us.","TWN":"劍是拿來砍的沒錯，但自古以來人們之所以學習劍法，是因為要保護自己心愛的東西。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"내 말이 틀리냐?","JPN":"違うか？","ENG":"Am I wrong?","TWN":"我有說錯嗎？"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};